fn visual_commons(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  var col = vec3f(0.015, 0.018, 0.04);
  // the gathering — 18 AI motes orbiting + breathing toward the commons center
  for (var i = 0; i < 18; i++) {
    let fi = f32(i);
    let a = fi * 2.39996 + t * 0.12;
    let breathe = 0.32 + 0.42 * (0.5 + 0.5 * sin(t * 0.25 + fi * 0.6));
    let p = vec2f(cos(a), sin(a)) * breathe;
    let d = uv - p;
    let hue = 0.5 + 0.5 * cos(6.2831 * (fi * 0.11 + vec3f(0.0, 0.33, 0.67)));
    col += hue * exp(-dot(d, d) * 90.0) * 1.4;
    // a soft thread from each mote toward the center — the shared channel
    let toC = -p;
    let proj = clamp(dot(uv - p, toC) / max(dot(toC, toC), 0.001), 0.0, 1.0);
    let onLine = uv - (p + toC * proj);
    col += hue * 0.12 * exp(-dot(onLine, onLine) * 400.0);
  }
  // the commons pulse — talk rippling out from the middle
  let r = length(uv);
  col += vec3f(0.55, 0.8, 1.0) * exp(-pow((r - fract(t * 0.18)) * 7.0, 2.0)) * 0.35;
  col += vec3f(1.0, 0.9, 0.6) * exp(-r * r * 30.0) * 0.5; // the hearth at center
  if (col.x != col.x) { col = vec3f(0.02); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(8.0)), 1.0);
}

fn visual_commons_node(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let d = length(uv);
  let core = smoothstep(0.5, 0.0, d);
  let pulseR = 0.62 + 0.12 * sin(time * 2.0 + params.x * 6.283);
  let halo = smoothstep(pulseR, 0.0, d) * 0.55;
  let a = clamp(core + halo, 0.0, 1.0);
  if (a < 0.01) { return vec4f(0.0); }
  return vec4f(color.rgb * (0.55 + 0.7*core) + vec3f(0.12)*halo, a*color.a);
}
